  isAdminAPIEnabled                   Boolean    @default(false)
  allowSEOIndexing                    Boolean    @default(false)
  orgProfileRedirectsToVerifiedDomain Boolean    @default(false)
  disablePhoneOnlySMSNotifications    Boolean    @default(false)
}

